import{c as a,Q as t,j as s,m as i}from"./chunks/framework.DVkeSyfh.js";const m=JSON.parse('{"title":"Поиск и запись тегов","description":"","frontmatter":{},"headers":[],"relativePath":"ru/search-and-tags.md","filePath":"ru/search-and-tags.md","lastUpdated":null}'),r={name:"ru/search-and-tags.md"};function o(c,e,l,d,n,p){return t(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="поиск-и-запись-тегов" tabindex="-1">Поиск и запись тегов <a class="header-anchor" href="#поиск-и-запись-тегов" aria-label="Permalink to &quot;Поиск и запись тегов&quot;">​</a></h1><p>Эта страница описывает search tabs, поверхность classifier filtering и явный workflow записи genre tags. Используйте ее, когда библиотека уже просканирована и нужно найти полезных соседей, собрать временный сет или решить, стоит ли сохранять MAEST genres обратно в файлы.</p><h2 id="режимы-поиска" tabindex="-1">Режимы поиска <a class="header-anchor" href="#режимы-поиска" aria-label="Permalink to &quot;Режимы поиска&quot;">​</a></h2><p>Search panel имеет отдельные tabs.</p><p>Выбирайте tab по намерению:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Что делает</th><th>Когда использовать</th></tr></thead><tbody><tr><td>SONARA</td><td>Ищет по объяснимым playlist features и custom mixer weights.</td><td>Нужны DJ-transition candidates и контроль rhythm, tempo, timbre, dynamics или harmonic balance.</td></tr><tr><td>MERT</td><td>Ищет от выбранных seed tracks в MERT embedding space.</td><td>Нужна audio-model similarity без настройки feature weights.</td></tr><tr><td>CLAP</td><td>Ищет CLAP audio embeddings по text prompt.</td><td>Вы знаете нужный sound или mood, но seed track нет.</td></tr><tr><td>CLASS</td><td>Фильтрует по promoted classifier scores.</td><td>Нужен переиспользуемый personal signal, обученный в Rhythm Lab.</td></tr></tbody></table><p>Library browser также имеет preset filter <code>syncopated</code>. Он выбирает tracks, у которых сохраненная MAEST metadata содержит <code>maest_syncopated_rhythm = true</code>, и может комбинироваться с обычным library text search и workflow add-filtered-tracks.</p><p>CLASS tab содержит classifier controls, найденные из promoted <code>models/classifiers/*/model.json</code> metadata. Каждый promoted classifier можно проанализировать из UI, а его slider фильтрует library и add-filtered-tracks workflow по <code>track_classifier_scores.score</code>.</p><h3 id="sonara-search" tabindex="-1">SONARA search <a class="header-anchor" href="#sonara-search" aria-label="Permalink to &quot;SONARA search&quot;">​</a></h3><p>SONARA - основной explainable seed-search path. Он отправляет selected seed tracks, optional lookback tracks, limit, minimum similarity, mixer weights и modifiers в <code>/api/search/sonara</code>.</p><p>Mixer weights:</p><ul><li><code>timbre</code></li><li><code>rhythm</code></li><li><code>dynamics</code></li><li><code>harmonic</code></li><li><code>tempo</code></li></ul><p>Modifiers:</p><ul><li><code>energy</code></li><li><code>valence</code></li><li><code>acousticness</code></li><li><code>brightness</code></li><li><code>rhythm_density</code></li><li><code>dynamic_range</code></li><li><code>loudness</code></li></ul><p>Backend все еще принимает preset mode names для compatibility:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>balanced, vibe, sound, dj_transition, custom</span></span></code></pre></div><p>Active UI path использует custom mixer.</p><p>Начинайте с SONARA, когда нужны explainable results. Увеличивайте или уменьшайте mixer weights, чтобы сдвигать поиск к transition fit, rhythmic feel, harmonic similarity или overall sound.</p><h3 id="mert-search" tabindex="-1">MERT search <a class="header-anchor" href="#mert-search" aria-label="Permalink to &quot;MERT search&quot;">​</a></h3><p>MERT seed search отправляет seed tracks, lookback tracks, limit и optional minimum similarity в <code>/api/search</code>. Он ранжирует tracks в MERT embedding space.</p><p>Используйте MERT после <code>dj-sim analyze --adapter mert</code> или соответствующей UI analysis job. Если results пустые или устарели, проверьте, есть ли у candidate tracks MERT embeddings.</p><h3 id="clap-text-search" tabindex="-1">CLAP text search <a class="header-anchor" href="#clap-text-search" aria-label="Permalink to &quot;CLAP text search&quot;">​</a></h3><p>CLAP text search отправляет text prompt, limit, optional minimum similarity и device в <code>/api/search/text</code>. Он ранжирует CLAP audio vectors относительно CLAP text vector.</p><p>Concrete English prompts обычно работают лучше:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Melancholic minimal house with broken drums, warm chords, no vocals</span></span>
<span class="line"><span>Dark hypnotic techno with sparse percussion and deep rolling bass</span></span>
<span class="line"><span>Organic microhouse with soft pads, plucked textures, and spacious mood</span></span></code></pre></div><p>Используйте CLAP для exploratory digging. Включайте в prompt musical texture, mood, tempo feel, vocal presence или instrumentation вместо reliance только на genre name.</p><h3 id="class-classifiers" tabindex="-1">CLASS / classifiers <a class="header-anchor" href="#class-classifiers" aria-label="Permalink to &quot;CLASS / classifiers&quot;">​</a></h3><p>CLASS tab предназначен для classifier-driven workflows, а не similarity search. Он показывает promoted classifiers, найденные из <code>models/classifiers/*/model.json</code>:</p><ul><li><code>Analyze &lt;classifier&gt;</code> запускает cancellable classifier job.</li><li>Каждый classifier slider фильтрует library server-side по stored classifier score.</li><li>Metadata dialog показывает classifier scores, confidence, label, feature set и model file ниже SONARA features.</li></ul><p>Promoted classifiers требуют promoted model file и feature-complete tracks. Они не анализируют аудио напрямую; сначала запустите SONARA, MERT и MAEST для треков, которые нужно оценить.</p><p>Используйте CLASS filters после scoring promoted classifier. High score означает, что model считает track соответствующим positive label профиля; это workflow hint, а не гарантия.</p><h2 id="запись-тегов" tabindex="-1">Запись тегов <a class="header-anchor" href="#запись-тегов" aria-label="Permalink to &quot;Запись тегов&quot;">​</a></h2><p>MAEST genre saving пишет одну нормализованную semicolon-separated genre string, например:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tech House; Minimal; Techno</span></span></code></pre></div><p>MAEST category prefixes вроде <code>Electronic---</code> удаляются перед записью.</p><p>Format-specific genre fields:</p><ul><li>MP3, WAV, AIFF ID3 tags: <code>TCON</code></li><li>FLAC и Vorbis-style tags: <code>GENRE</code></li><li>MP4, M4A, ALAC: <code>©gen</code></li></ul><p>WAV genre writing использует Mutagen <code>WAVE</code> support, сохраняет значение <code>TCON</code> и проверяет, что сохраненное значение читается после записи. Он не запускает custom RIFF repair step. Если WAV write или readback fails, этот track помечается failed, а batch продолжается.</p><p>Используйте tag writing только после проверки MAEST labels в приложении. Он предназначен для сохранения generated genre labels в стандартное поле genre; это не general metadata editor, и его не нужно использовать для изменения title, artist, album, BPM, key или custom tags.</p>`,39)])])}const u=a(r,[["render",o]]);export{m as __pageData,u as default};
